SELECT JB.CO_ID, JB.JB_ID, JB.JB_STS, JB.FILE_ID, JB.FILE_NM, JB.TOTAL_ROWS, JB.JB_PROG, JB.CRE_USR_ID, JB.CRE_DT, JB.UPD_USR_ID, JB.UPD_DT FROM COM_XPT_JB JB LEFT JOIN COM_FILE FILE ON ( FILE.CO_ID = JB.CO_ID AND FILE.FILE_ID = JB.FILE_ID ) WHERE JB.CO_ID = #{coId} AND JB.CRE_USR_ID = #{creUsrId}
AND JB.JB_ID = #{jbId}
AND JB.JB_ID IN
#{id}
ORDER BY JB.UPD_DT DESC
LIMIT #{pagination.pageSize} OFFSET (#{pagination.current} - 1) * #{pagination.pageSize}

 SELECT COUNT(*)
	FROM COM_XPT_JB
	WHERE CO_ID = #{coId}
	AND CRE_USR_ID = #{creUsrId}

		AND JB_ID = #{jbId}

