	UPDATE COM_XPT_JB
       SET JB_PROG = #{jbProg},
       UPD_DT = NOW(),
       UPD_USR_ID = 'SYSTEM'
    WHERE CO_ID = #{coId}
      AND JB_ID = #{jbId}
